const fs = require('fs');
const path = require('path');
const config = require('../config.js');
const { AppError } = require('./errors.js');

const SUPPORTED_FORMATS = ['csv', 'json'];

function parseFormat(args) {
  const idx = args.indexOf('--format');
  const format = idx >= 0 ? args[idx + 1] : 'csv';
  if (!SUPPORTED_FORMATS.includes(format)) {
    throw new AppError(`unsupported format: ${format}`, 2);
  }
  return format;
}

function toCSV(records) {
  const headers = Object.keys(records[0]);
  const rows = records.map((r) => headers.map((h) => r[h]).join(','));
  return [headers.join(','), ...rows].join('\n');
}

function writeExport(entity, records, format) {
  if (!fs.existsSync(config.outputDir)) {
    fs.mkdirSync(config.outputDir);
  }
  const filename = path.join(config.outputDir, `${entity}.${format}`);
  const content = format === 'json'
    ? JSON.stringify(records, null, 2)
    : toCSV(records);
  fs.writeFileSync(filename, content);
  return filename;
}

module.exports = { parseFormat, writeExport };

